485→                                editorState: postData?.content,
486→                                nodes: [HeadingNode, ImageNode, QuoteNode],
487→                                onError(error) {
488→                                    throw error;
489→                                },
490→                            }}>
491→                                <RichTextPlugin
492→                                    contentEditable={<ContentEditable />}
493→                                    ErrorBoundary={LexicalErrorBoundary}
494→                                />
495→                            </LexicalComposer>
496→                        )}
497→                    </div>
498→                </article>
499→
500→                {/* Toast notification */}
501→            <AnimatePresence>
502→                {(bookmarkedMessage) && (
503→                    <motion.div
504→                        className="cv-toast"
505→                        initial={{ opacity: 0, y: 8 }}
506→                        animate={{ opacity: 1, y: 0 }}
507→                        exit={{ opacity: 0, y: 8 }}
508→                        transition={{ duration: 0.2, ease: "easeOut" }}
509→                    >
510→                        {bookmarkedMessage}
511→                    </motion.div>
512→                )}
513→            </AnimatePresence>
514→            </div>
515→
516→            {showRepostModal && postData && (
517→                <RepostModal
518→                    journal={{
519→                        id: postData.journalId,
520→                        title: postData.title,
521→                        users: {
522→                            id: postData.userId,
523→                            name: postData.name,
524→                            image_url: postData.avatar,
525→                            badge: postData.badge
526→                        }
527→                    }}
528→                    onClose={(result) => {
529→                        setShowRepostModal(false);
530→                        if(result === 'success'){
531→                            setBookmarkedMessage('Post was reposted');
532→                            if(timeOutRefBookmark.current){
533→                                clearTimeout(timeOutRefBookmark.current);
534→                            }
535→                            timeOutRefBookmark.current = setTimeout(() => {
536→                                setBookmarkedMessage('');
537→                            }, 2500);
538→                        }
539→                    }}
540→                />
541→            )}
542→        </>
543→    )
544→}
545→
546→export default ContentView;
